"""
generate-assets.py
GÃ©nÃ¨re les icÃ´nes PNG pour Images Manager.
Les images sont embarquÃ©es en base64 â aucune dÃ©pendance externe requise.
"""
import base64, os

os.makedirs("assets", exist_ok=True)

ICONS = {
    "icon-512.png": "",
    "icon-192.png": "",
    "favicon.png": "",
    "icon.png": "",
}

for filename, b64data in ICONS.items():
    dest = os.path.join("assets", filename)
    with open(dest, "wb") as f:
        f.write(base64.b64decode(b64data))
    print(f"OK: {dest} ({os.path.getsize(dest)} bytes)")

# Copies nÃ©cessaires pour app.json
import shutil
shutil.copy("assets/icon.png",    "assets/adaptive-icon.png")

# Splash simple (fond bleu uni â l'image n'est pas utilisÃ©e en web)
try:
    from PIL import Image
    img = Image.new("RGB", (1242, 2436), (37, 99, 235))
    img.save("assets/splash.png")
    print("OK: assets/splash.png (Pillow)")
except ImportError:
    # Pillow absent : copie l'icÃ´ne comme splash (acceptable)
    shutil.copy("assets/icon.png", "assets/splash.png")
    print("OK: assets/splash.png (fallback icone)")

print("\nTous les assets generÃ©s.")
